// --------------------------------------------------
// Lightweight waves & tide (pre-computed, max 40 sprites)
// --------------------------------------------------
let _waveSprites = null;

function _buildWaveSprites(system) {
  const land = system.eco.land;
  const E_OCEAN = land.E_OCEAN;
  const out = [];
  const candidates = [];
  for (const tile of land.terra) {
    if (!tile.ocean) continue;
    if (E_OCEAN - tile.elevation > 2.5) continue;
    const ns = [
      land.getTile(tile.u - 1, tile.v),
      land.getTile(tile.u + 1, tile.v),
      land.getTile(tile.u, tile.v - 1),
      land.getTile(tile.u, tile.v + 1),
    ];
    if (ns.some(n => n && !n.ocean)) {
      candidates.push(tile);
    }
  }
  // Deterministic shuffle, keep max 40
  candidates.sort((a, b) => ((a.u * 131 + a.v * 197) % 256) - ((b.u * 131 + b.v * 197) % 256));
  for (let i = 0; i < Math.min(40, candidates.length); i++) {
    const t = candidates[i];
    out.push({ u: t.u, v: t.v, ph: t.u * 0.5 + t.v * 0.3 });
  }
  return out;
}

function _drawTide(params) {
  const { GRID_SCALE, PIXELS_PER_Z } = params;
  const z_ocean = system.eco.land.E_OCEAN * PIXELS_PER_Z;
  const t = millis() * 0.001;

  // Rebuild once when terrain settles, or every 120 frames during eruption
  if (!_waveSprites || (simulation.getPhase() <= 2 && frameCount % 120 === 0)) {
    _waveSprites = _buildWaveSprites(system);
  }
  if (_waveSprites.length === 0) return;

  // Global tide offset (slow rise and fall)
  const tide = Math.sin(t * 0.3) * 1.5;

  noStroke();
  // Batched triangles — single draw call for all waves
  fill(215, 238, 255, 110);
  beginShape(TRIANGLES);
  for (const w of _waveSprites) {
    const cx = GRID_SCALE * (w.u + 0.5);
    const cy = GRID_SCALE * (w.v + 0.5);
    const wz = z_ocean + tide + 0.4 + Math.sin(t * 1.8 + w.ph) * 1.0;
    const hw = GRID_SCALE * 0.35;
    // Simple flat quad (2 triangles)
    vertex(cx - hw, cy - hw * 0.3, wz);
    vertex(cx + hw, cy - hw * 0.3, wz);
    vertex(cx + hw, cy + hw * 0.3, wz + 0.5);
    vertex(cx - hw, cy - hw * 0.3, wz);
    vertex(cx + hw, cy + hw * 0.3, wz + 0.5);
    vertex(cx - hw, cy + hw * 0.3, wz + 0.5);
  }
  endShape();
}

