function buildVolcanoCinematic() {
  const { GRID_SCALE, GRID_U, GRID_V } = system.params;
  const vc = volcano.getCenter();
  const px = GRID_SCALE * (vc.u + 0.5 - GRID_U / 2);
  const py = GRID_SCALE * (GRID_V / 2 - vc.v - 0.5);

  return [
    // Wide establishing shot
    { panX: 0, panY: 0, angleX: 0.6, angleY: 0, distance: 1800, dwell: 600 },
    // Zoom into volcano center
    { panX: px, panY: py, angleX: 0.4, angleY: Math.PI * 0.3, distance: 800, dwell: 960 },
    // Low angle view of eruption
    { panX: px, panY: py, angleX: 0.15, angleY: Math.PI * 1.0, distance: 600, dwell: 800 },
    // Overhead view
    { panX: px * 0.5, panY: py * 0.5, angleX: 0.7, angleY: Math.PI * 1.7, distance: 1200, dwell: 800 },
  ];
}

// Cinematic shots only use volcano-centered views now (no decor POIs)

function updateCinematicCamera() {
  if (cinematicShots.length === 0) return;
  const shot = cinematicShots[cinematicIndex];

  const baseDt = 1000 / CINEMATIC_BASE_FPS;
  const dt = baseDt;
  const lerpFactor = 1 - Math.pow(1 - CINEMATIC_LERP, dt / baseDt);

  cam.panX += (shot.panX - cam.panX) * lerpFactor;
  cam.panY += (shot.panY - cam.panY) * lerpFactor;
  cam.angleX += (shot.angleX - cam.angleX) * lerpFactor;
  cam.distance += (shot.distance - cam.distance) * lerpFactor;

  let yawDiff = shot.angleY - cam.angleY;
  while (yawDiff > Math.PI) yawDiff -= TWO_PI;
  while (yawDiff < -Math.PI) yawDiff += TWO_PI;
  cam.angleY += yawDiff * lerpFactor;

  shot.angleY += CINEMATIC_ORBIT * (dt / baseDt);

  cinematicTimer += dt;
  if (cinematicTimer >= shot.dwell * baseDt) {
    cinematicTimer = 0;
    cinematicIndex = (cinematicIndex + 1) % cinematicShots.length;
  }
}

