/**
 * Volcanic land color: black basalt → brown → green as vegetation increases.
 * Called per-tile by draw3D via the landColor callback.
 */
function volcanicLandColor(tile, land, tileGreenness, lavaHeat) {
  if (!tile) return color(40, 40, 38);
  const e = tile.elevation;
  const E_OCEAN = land.E_OCEAN;

  // Underwater — blueish
  if (e < E_OCEAN) {
    const depth = Math.min(1, (E_OCEAN - e) / Math.max(1, land.E_MAX - land.E_MIN));
    const b = Math.floor(140 - depth * 85);
    return color(20, 50 + Math.floor(depth * 20), b);
  }

  // Greenness from vegetation (0 = bare basalt, 1 = lush)
  const key = `${tile.u},${tile.v}`;
  const greenness = tileGreenness ? (tileGreenness.get(key) ?? 0) : 0;

  // Normalize elevation
  const above = Math.max(0, e - E_OCEAN);
  const range = Math.max(1e-9, land.E_MAX - E_OCEAN);
  const n = Math.min(1, above / range);

  // Jitter for natural variation
  const jitter = ((tile.u * 131 + tile.v * 197) % 17) - 8;

  // --- Base: volcanic basalt (dark black/gray) ---
  let rockR, rockG, rockB;
  if (n < 0.07) {
    // Beach band — dark volcanic sand
    rockR = 50 + n * 60;
    rockG = 45 + n * 50;
    rockB = 40 + n * 40;
  } else if (n < 0.85) {
    // Mid elevation — dark basalt
    rockR = 35 + n * 20;
    rockG = 32 + n * 15;
    rockB = 30 + n * 10;
  } else {
    // Peaks — slightly lighter rock
    rockR = 55 + n * 15;
    rockG = 52 + n * 12;
    rockB = 50 + n * 10;
  }

  // Add jitter
  rockR = Math.max(0, Math.min(80, rockR + jitter * 0.5));
  rockG = Math.max(0, Math.min(75, rockG + jitter * 0.4));
  rockB = Math.max(0, Math.min(70, rockB + jitter * 0.3));

  // --- Target: vegetated green ---
  let vegR, vegG, vegB;
  if (n < 0.07) {
    // Beach with some moss
    vegR = 130; vegG = 145; vegB = 95;
  } else if (n < 0.55) {
    // Lush lowland
    vegR = 45 + n * 20; vegG = 100 + n * 80; vegB = 40 + n * 20;
  } else if (n < 0.85) {
    // Upland forest
    vegR = 35; vegG = 80 - n * 30; vegB = 35;
  } else {
    // Alpine — sparse green on rock
    vegR = 70; vegG = 85; vegB = 60;
  }

  // --- Blend basalt → green based on greenness ---
  let r = Math.round(rockR + (vegR - rockR) * greenness);
  let g = Math.round(rockG + (vegG - rockG) * greenness);
  let b = Math.round(rockB + (vegB - rockB) * greenness);

  // --- Lava heat overlay: black rock → glowing red → bright orange ---
  const heat = lavaHeat ? (lavaHeat.get(key) ?? 0) : 0;
  if (heat > 0) {
    // Molten lava: dark red at low heat → bright orange-yellow at full heat
    const lavaR = Math.floor(80 + 175 * heat);
    const lavaG = Math.floor(20 + 100 * heat * heat);
    const lavaB = Math.floor(5 + 20 * heat * heat);
    r = Math.round(r + (lavaR - r) * heat);
    g = Math.round(g + (lavaG - g) * heat);
    b = Math.round(b + (lavaB - b) * heat);
  }

  return color(r, g, b);
}

function exitCinematic() {
  cinematicMode = false;
  if (hintEl) {
    hintEl.html("[WASD] Pan &nbsp; [Q/E] Orbit &nbsp; [Scroll] Zoom &nbsp; [&uarr;&darr;] Speed &nbsp; [Space] Pause &nbsp; [R] Reset &nbsp; [P] Cinematic");
  }
}

// --------------------------------------------------
