function keyPressed() {
  if (key === 'p' || key === 'P') {
    if (!cinematicMode) {
      cinematicShots = buildVolcanoCinematic();
      cinematicIndex = 0;
      cinematicTimer = 0;
      cam.resetVelocity();
      cinematicMode = true;
    } else {
      exitCinematic();
    }
    return;
  }

  if (key === 'r' || key === 'R') {
    exitCinematic();
    initTerrain();
    return;
  }

  // Speed controls: arrow up/down or +/-
  if (keyCode === UP_ARROW || key === '+' || key === '=') {
    simulation.speedUp();
    return;
  }
  if (keyCode === DOWN_ARROW || key === '-' || key === '_') {
    simulation.speedDown();
    return;
  }

  // Space to pause/unpause
  if (key === ' ') {
    simulation.paused = !simulation.paused;
    return;
  }

  if (cinematicMode) {
    exitCinematic();
    return;
  }
}

