      // Don't push land below ocean
      if (!tile.ocean && newElev > E_OCEAN + 0.5) {
        tile.setElevation(newElev);
        changed = true;
      } else if (tile.ocean) {
        tile.setElevation(newElev);
        changed = true;
      }
    }

    if (changed) {
      world.updateAdjacent();
      world.calculateCorners();
      world.calculateTemperature();
      world.calculateHumidity();
      world.calculateBiomassMax();
    }
  }

  /** Phase 0: Show a subtle underwater mound */
  _showUnderwaterVolcano(progress) {
    const world = this.world;
    const E_OCEAN = world.E_OCEAN;
    // Only show tiles near the volcano center as a slight raised area underwater
    const radius = 6 + progress * 4; // grows slightly over time
    const strength = 0.1 + progress * 0.15; // how much of target to reveal

    let changed = false;
    for (const tile of world.terra) {
      const du = tile.u - this.centerU;
      const dv = tile.v - this.centerV;
      const dist = Math.sqrt(du * du + dv * dv);

      if (dist < radius) {
        const idx = tile.u * world.V + tile.v;
        const target = this.targetElevations[idx];
        // Only show what's below ocean level (underwater mound)
        const underwaterTarget = Math.min(target, E_OCEAN - 0.5);
        const falloff = 1 - (dist / radius);
        const newElev = world.DEEP_OCEAN + (underwaterTarget - world.DEEP_OCEAN) * strength * falloff;

        if (Math.abs(tile.elevation - newElev) > 0.01) {
          tile.setElevation(newElev);
          tile.ocean = true;
          changed = true;
        }
      }
    }

    if (changed) {
      world.updateAdjacent();
      world.calculateCorners();
    }
  }

  /** Phase 1: Eruption — terrain rises toward target */
  _eruptionPhase(progress) {
    const world = this.world;
    const E_OCEAN = world.E_OCEAN;

    // Eruption radius grows over time, from center outward
    const maxReach = this.maxRadius * (0.3 + progress * 0.7);
    // How aggressively terrain approaches target
    const globalStrength = 0.2 + progress * 0.8;

    let changed = false;
    for (const tile of world.terra) {
      const du = tile.u - this.centerU;
      const dv = tile.v - this.centerV;
      const dist = Math.sqrt(du * du + dv * dv);

      if (dist > maxReach) continue;

      const idx = tile.u * world.V + tile.v;
      const target = this.targetElevations[idx];

      // Distance falloff — center tiles reach target first
      const distFactor = 1 - Math.pow(dist / maxReach, 1.5);
      const strength = globalStrength * distFactor;

      const newElev = world.DEEP_OCEAN + (target - world.DEEP_OCEAN) * strength;

      if (Math.abs(tile.elevation - newElev) > 0.05) {
        tile.setElevation(newElev);
        tile.ocean = newElev <= E_OCEAN;

        // Snap to avoid z-fighting (same logic as world.js)
        if (!tile.ocean) {
          const landGap = tile.elevation - E_OCEAN;
          if (landGap > 0 && landGap < 1.0) {
            tile.setElevation(E_OCEAN + 1.0);
          }
        } else {
          const shoreGap = Math.abs(tile.elevation - E_OCEAN);
          if (shoreGap < 1.0) {
            tile.setElevation(E_OCEAN - 1.0);
          }
        }

        changed = true;
      }
    }

    if (changed) {
      world.updateAdjacent();
      world.calculateCorners();
      world.calculateTemperature();
      world.calculateHumidity();
      world.calculateBiomassMax();
    }
  }

  /** Lava flows down from volcano center — heat radiates outward */
  _updateLavaFlows(progress) {
    const world = this.world;
    const E_OCEAN = world.E_OCEAN;

    // Multiple lava flow arms radiating from crater
    const numFlows = 3 + Math.floor(progress * 4);
    const flowLength = Math.floor(3 + progress * 15);

    for (let f = 0; f < numFlows; f++) {
      // Each flow has a stable direction (seeded by f)
      const angle = (f / numFlows) * Math.PI * 2 + Math.sin(f * 7.3) * 0.5;
      let fu = this.centerU;
      let fv = this.centerV;

      for (let d = 0; d < flowLength; d++) {
        fu += Math.cos(angle + Math.sin(d * 0.3 + f) * 0.3);
        fv += Math.sin(angle + Math.sin(d * 0.3 + f) * 0.3);
        const tu = Math.round(fu);
        const tv = Math.round(fv);
        const tile = world.getTile(tu, tv);
        if (!tile) break;

        // Heat decreases with distance from center
        const heat = Math.max(0, 1.0 - (d / flowLength) * 0.7);
        const key = `${tu},${tv}`;
        const existing = this.lavaHeat.get(key) || 0;
        this.lavaHeat.set(key, Math.min(1, Math.max(existing, heat)));

        // Lava flowing into ocean creates new land!
        if (tile.ocean && tile.elevation > E_OCEAN - 3 && progress > 0.4) {
          tile.setElevation(E_OCEAN + 0.5 + Math.random());
          tile.ocean = false;
        }
      }
    }

    // Heat the center intensely
    for (let du = -2; du <= 2; du++) {
      for (let dv = -2; dv <= 2; dv++) {
        const key = `${this.centerU + du},${this.centerV + dv}`;
        this.lavaHeat.set(key, 1.0);
      }
    }
  }

  /** Cool lava heat over time */
  _coolLavaHeat(rate) {
    for (const [key, heat] of this.lavaHeat) {
      const newHeat = heat - rate;
      if (newHeat <= 0) {
        this.lavaHeat.delete(key);
      } else {
        this.lavaHeat.set(key, newHeat);
      }
    }
  }

  /** Get lava heat map for terrain color rendering */
  getLavaHeat() {
    return this.lavaHeat;
  }

  /** Snap all tiles to their final target elevation */
  _finalizeTerrainToTarget() {
    const world = this.world;
    const E_OCEAN = world.E_OCEAN;

    for (const tile of world.terra) {
      const idx = tile.u * world.V + tile.v;
      const target = this.targetElevations[idx];
      tile.setElevation(target);
      tile.ocean = target <= E_OCEAN;

      if (!tile.ocean) {
        const landGap = tile.elevation - E_OCEAN;
        if (landGap > 0 && landGap < 1.0) {
          tile.setElevation(E_OCEAN + 1.0);
        }
      } else {
        const shoreGap = Math.abs(tile.elevation - E_OCEAN);
        if (shoreGap < 1.0) {
          tile.setElevation(E_OCEAN - 1.0);
        }
      }
    }

    world.updateAdjacent();
    world.calculateCorners();
    world.calculateTemperature();
    world.calculateHumidity();
    world.calculateBiomassMax();
  }

  /** Spawn lava particles — dramatic eruption from volcano center */
  _spawnLavaParticles(progress) {
    if (this.lavaParticles.length > 100) return;

    const world = this.world;
    const E_OCEAN = world.E_OCEAN;

    // Explosive eruption from volcano summit
    const centerTile = world.getTile(this.centerU, this.centerV);
    const peakZ = centerTile ? centerTile.elevation : E_OCEAN;

    // Main eruption plume — lava bombs shooting upward from crater
    const plumeCount = Math.floor(5 + progress * 10);
    for (let i = 0; i < plumeCount; i++) {
      const spread = 1.5 + Math.random() * 2;
      this.lavaParticles.push({
        u: this.centerU + (Math.random() - 0.5) * spread,
        v: this.centerV + (Math.random() - 0.5) * spread,
        z: peakZ + 2,
        vz: 0.5 + Math.random() * 1.2,  // shoot upward
        vu: (Math.random() - 0.5) * 0.06,
        vv: (Math.random() - 0.5) * 0.06,
        life: 1.0,
        decay: 0.006 + Math.random() * 0.008,
        size: 1.5 + Math.random() * 3,
        type: "lava",
      });
    }

    // Lava flows — particles spreading outward along the ground
    const flowCount = Math.floor(3 + progress * 5);
    const flowRadius = 2 + progress * 6;
    for (let i = 0; i < flowCount; i++) {
      const angle = Math.random() * Math.PI * 2;
      const r = Math.random() * flowRadius;
      const pu = this.centerU + Math.cos(angle) * r;
      const pv = this.centerV + Math.sin(angle) * r;
      const tile = world.getTile(Math.round(pu), Math.round(pv));
      if (!tile) continue;

      this.lavaParticles.push({
        u: pu,
        v: pv,
        z: Math.max(tile.elevation, E_OCEAN - 1),
        vz: 0.02 + Math.random() * 0.05,
        vu: Math.cos(angle) * 0.02,
        vv: Math.sin(angle) * 0.02,
        life: 1.0,
        decay: 0.003 + Math.random() * 0.005,
        size: 2 + Math.random() * 3,
        type: "flow",  // glowing lava flow on ground
      });
    }
  }

  /** Spawn massive steam clouds where hot lava meets ocean */
  _spawnSteamParticles() {
    if (this.steamParticles.length > 80) return;

    const world = this.world;
    const E_OCEAN = world.E_OCEAN;

    // Sample random tiles near volcano center for steam (avoid full scan)
    const sampleCount = 20;
    const radius = 15;
    for (let i = 0; i < sampleCount && this.steamParticles.length < 80; i++) {
      const ru = this.centerU + Math.floor((Math.random() - 0.5) * radius * 2);
      const rv = this.centerV + Math.floor((Math.random() - 0.5) * radius * 2);
      const tile = world.getTile(ru, rv);
      if (!tile || tile.ocean) continue;
      const above = tile.elevation - E_OCEAN;
      if (above > 4) continue;

      const neighbors = [
        world.getTile(tile.u - 1, tile.v),
        world.getTile(tile.u + 1, tile.v),
        world.getTile(tile.u, tile.v - 1),
        world.getTile(tile.u, tile.v + 1),
      ];
      if (!neighbors.some(n => n && n.ocean)) continue;

      this.steamParticles.push({
        u: tile.u + (Math.random() - 0.5) * 1.2,
        v: tile.v + (Math.random() - 0.5) * 1.2,
        z: E_OCEAN + Math.random() * 1,
        vz: 0.15 + Math.random() * 0.35,
        life: 1.0,
        decay: 0.004 + Math.random() * 0.008,
        size: 3 + Math.random() * 5,
      });
    }
  }

  /** Rare volcanic re-eruption — lava flows, terrain grows, wildfire */
  _applyReEruption(simulation) {
    this.reEruptionTimer++;
    if (this.reEruptionTimer < this.reEruptionCooldown) return;
    this.reEruptionTimer = 0;
    this.reEruptionCooldown = 1000 + Math.floor(Math.random() * 1500);

    const world = this.world;
    const E_OCEAN = world.E_OCEAN;

    // Camera shake
    this.shakeOffset.x = (Math.random() - 0.5) * 15;
    this.shakeOffset.z = (Math.random() - 0.5) * 15;

    // Lava flow from volcano center — raises terrain and spawns particles
    const flowAngle = Math.random() * Math.PI * 2;
    const flowLength = 5 + Math.floor(Math.random() * 10);
    let changed = false;

    for (let d = 0; d < flowLength; d++) {
      const fu = Math.round(this.centerU + Math.cos(flowAngle) * d);
      const fv = Math.round(this.centerV + Math.sin(flowAngle) * d);
      const tile = world.getTile(fu, fv);
      if (!tile) continue;

      // Raise terrain slightly (island grows)
      if (!tile.ocean) {
        tile.setElevation(tile.elevation + 0.3);
        changed = true;
      } else if (tile.elevation > E_OCEAN - 2) {
        // Lava extends into shallow water — new land!
        tile.setElevation(E_OCEAN + 1.5);
        tile.ocean = false;
        changed = true;
      }

      // Spawn lava particles along the flow
      if (this.lavaParticles.length < 100) {
        for (let j = 0; j < 3; j++) {
          this.lavaParticles.push({
            u: fu + (Math.random() - 0.5),
            v: fv + (Math.random() - 0.5),
            z: tile.elevation + 1,
            vz: 0.1 + Math.random() * 0.3,
            vu: Math.cos(flowAngle) * 0.01,
            vv: Math.sin(flowAngle) * 0.01,
            life: 1.0,
            decay: 0.004 + Math.random() * 0.006,
            size: 2 + Math.random() * 2,
            type: "flow",
          });
        }
      }

      // Lava heat on re-eruption path
      this.lavaHeat.set(`${fu},${fv}`, 1.0);

      // Set tiles on fire (destroys vegetation)
      const fireRadius = 2;
      for (let du = -fireRadius; du <= fireRadius; du++) {
        for (let dv = -fireRadius; dv <= fireRadius; dv++) {
          const ft = world.getTile(fu + du, fv + dv);
          if (ft && !ft.ocean) {
            this.fireTiles.add(`${ft.u},${ft.v}`);
          }
        }
      }
    }

    if (changed) {
      world.updateAdjacent();
      world.calculateCorners();
    }

    // Start wildfire timer
    this.fireTimer = 120;
  }

  /** Spread fire and destroy vegetation */
  _spreadFire() {
    if (!this.vegetationManager) return;

    // Burn vegetation on fire tiles
    for (const key of this.fireTiles) {
      const plants = this.vegetationManager.plants.get(key);
      if (plants && plants.length > 0) {
        // Remove one plant per fire tick
        const removed = plants.pop();
        if (removed) this.vegetationManager.totalPlants--;

        // Fire particle
        if (this.fireParticles.length < 60) {
          const [uStr, vStr] = key.split(",");
          this.fireParticles.push({
            u: parseInt(uStr) + (Math.random() - 0.5) * 0.5,
            v: parseInt(vStr) + (Math.random() - 0.5) * 0.5,
            z: 0, // will use tile elevation in draw
            life: 1.0,
            decay: 0.02 + Math.random() * 0.02,
            size: 2 + Math.random() * 3,
          });
        }
      }
    }

    // Spread fire to adjacent tiles with vegetation (10% chance)
    const newFire = [];
    for (const key of this.fireTiles) {
      if (Math.random() > 0.1) continue;
      const [uStr, vStr] = key.split(",");
      const u = parseInt(uStr), v = parseInt(vStr);
      for (const [du, dv] of [[-1,0],[1,0],[0,-1],[0,1]]) {
        const nk = `${u+du},${v+dv}`;
        if (!this.fireTiles.has(nk) && this.vegetationManager.plants.has(nk)) {
          newFire.push(nk);
        }
      }
    }
    for (const nk of newFire) this.fireTiles.add(nk);

    // Clear fire when timer runs out
    if (this.fireTimer <= 1) {
      this.fireTiles.clear();
      this.fireParticles = [];
    }

    // Update fire particles
    for (let i = this.fireParticles.length - 1; i >= 0; i--) {
      const p = this.fireParticles[i];
      p.life -= p.decay;
      p.z += 0.1;
      if (p.life <= 0) this.fireParticles.splice(i, 1);
    }
  }

  /** Update particle positions and lifetimes */
  _updateParticles() {
    // Lava particles
    for (let i = this.lavaParticles.length - 1; i >= 0; i--) {
      const p = this.lavaParticles[i];
      p.u += p.vu;
      p.v += p.vv;
      if (p.type === "flow") {
        // Ground flows move slowly outward, barely rising
        p.z += p.vz;
        p.vz *= 0.95;
      } else {
        // Airborne lava bombs arc upward then fall
        p.z += p.vz;
        p.vz -= 0.02; // gravity
      }
      p.life -= p.decay;
      if (p.life <= 0) {
        this.lavaParticles.splice(i, 1);
      }
    }

    // Steam particles — billow upward and expand
    for (let i = this.steamParticles.length - 1; i >= 0; i--) {
      const p = this.steamParticles[i];
      p.z += p.vz;
      p.u += (Math.random() - 0.5) * 0.02; // wind drift
      p.v += (Math.random() - 0.5) * 0.02;
      p.life -= p.decay;
      p.size *= 1.015; // expand as rising
      if (p.life <= 0) {
        this.steamParticles.splice(i, 1);
      }
    }
  }

  /**
   * Draw volcano effects (lava & steam particles).
   * Called within the world-transform push/pop.
   */
  draw(params) {
    const { GRID_SCALE, PIXELS_PER_Z } = params;

    noStroke();

    // Lava particles — bright red/orange glowing
    for (const p of this.lavaParticles) {
      const x = GRID_SCALE * (p.u + 0.5);
      const y = GRID_SCALE * (p.v + 0.5);
      const z = PIXELS_PER_Z * p.z;

      push();
      translate(x, y, z);

      if (p.type === "flow") {
        // Ground lava flow — bright orange-red glow
        const r = Math.floor(220 + 35 * p.life);
        const g = Math.floor(80 * p.life + 30);
        const b = Math.floor(10 * p.life);
        fill(r, g, b, Math.floor(220 * p.life));
        sphere(p.size * (0.5 + p.life * 0.5));
        // Inner glow
        fill(255, 200, 50, Math.floor(100 * p.life));
        sphere(p.size * 0.4 * p.life);
      } else {
        // Airborne lava bomb — bright yellow core fading to dark red
        const r = Math.floor(255 * Math.min(1, p.life + 0.3));
        const g = Math.floor(160 * p.life);
        const b = Math.floor(30 * p.life);
        fill(r, g, b, Math.floor(255 * p.life));
        sphere(p.size * p.life);
        // Hot core
        if (p.life > 0.5) {
          fill(255, 255, 100, Math.floor(150 * (p.life - 0.5) * 2));
          sphere(p.size * 0.3);
        }
      }

      pop();
    }

    // Steam particles — thick white/gray billowing clouds
    for (const p of this.steamParticles) {
      const x = GRID_SCALE * (p.u + 0.5);
      const y = GRID_SCALE * (p.v + 0.5);
      const z = PIXELS_PER_Z * p.z;

      // Opacity decreases as steam rises and disperses
      const alpha = Math.floor(160 * p.life);
      // Color shifts from white to gray as it rises
      const brightness = Math.floor(200 + 55 * p.life);

      push();
      translate(x, y, z);
      fill(brightness, brightness, brightness + 10, alpha);
      // Large billowing cloud puffs
      const puffSize = p.size * GRID_SCALE * 0.2;
      ellipse(0, 0, puffSize, puffSize * 0.7);
      // Second smaller puff for volume
      translate(puffSize * 0.2, puffSize * 0.1, puffSize * 0.15);
      fill(brightness - 10, brightness - 5, brightness, Math.floor(alpha * 0.6));
      ellipse(0, 0, puffSize * 0.7, puffSize * 0.5);
      pop();
    }

    // Fire particles — orange/red flames
    for (const p of this.fireParticles) {
      const x = GRID_SCALE * (p.u + 0.5);
      const y = GRID_SCALE * (p.v + 0.5);
      const tile = this.world.getTile(Math.round(p.u), Math.round(p.v));
      const z = tile ? PIXELS_PER_Z * tile.elevation + p.z * 5 : p.z * 5;

      push();
      translate(x, y, z);
      const flicker = Math.sin(millis() * 0.01 + p.u * 10) * 0.3 + 0.7;
      fill(255 * flicker, 120 * p.life, 20, Math.floor(200 * p.life));
      sphere(p.size * p.life * 2);
      translate(0, 0, p.size * 3);
      fill(80, 80, 80, Math.floor(100 * p.life));
      ellipse(0, 0, p.size * 3, p.size * 2);
      pop();
    }
  }

  /** Get the volcano center for camera targeting */
  getCenter() {
    return { u: this.centerU, v: this.centerV };
  }

  isStable() {
    return this.terrainStable;
  }

  /** Get camera shake offset from earthquakes */
  getShakeOffset() {
    return this.shakeOffset;
  }
}

